// ============================================================
// MAIN.JS - SEARCH AND CATEGORY FILTERING FOR ARTICLES
// This script fetches feed.json (generated by Jekyll) and
// populates the article grid on the Articles page.
// It also handles search input and category filtering.
// ============================================================

// --- GLOBAL VARIABLES ---
let allArticles = [];   // Stores all articles loaded from feed.json
let activeCategory = 'all';  // Currently selected category filter

// --- LOAD ARTICLES FROM FEED.JSON ---
// This function runs when the page loads
// It fetches the JSON file that Jekyll generates from your blog posts
async function loadArticles() {
  try {
    // feed.json is generated by Jekyll from your _posts folder
    // relative_url ensures it works with any baseurl setting
    const response = await fetch('/feed.json');
    allArticles = await response.json();
    renderArticles(allArticles);
  } catch (error) {
    console.error('Failed to load articles:', error);
    document.getElementById('article-grid').innerHTML =
      '<p>Error loading articles. Make sure feed.json exists.</p>';
  }
}

// --- RENDER ARTICLES TO THE PAGE ---
// Takes an array of article objects and creates HTML cards for each
function renderArticles(articles) {
  const grid = document.getElementById('article-grid');
  const noResults = document.getElementById('no-results');

  // Show "no results" message if array is empty
  if (articles.length === 0) {
    grid.innerHTML = '';
    noResults.style.display = 'block';
    return;
  }

  noResults.style.display = 'none';

  // Build HTML for each article card
  // Template literal (backticks) lets us write HTML with ${variables}
  grid.innerHTML = articles.map(article => `
    <div class="grid-card">
      <div class="grid-card-img">
        <a href="${article.url}">
          <img src="${article.image}" alt="${article.title}"
               onerror="this.src='/assets/img/default-thumb.png'">
        </a>
      </div>
      <div class="grid-card-body">
        <span class="article-badge">${article.category}</span>
        <span class="article-card-date">${formatDate(article.date)}</span>
        <h3 class="article-card-title" style="font-size:12px;margin:6px 0;">
          <a href="${article.url}">${article.title}</a>
        </h3>
        <p style="font-size:18px;color:#404040;">${article.excerpt}</p>
        <a href="${article.url}" class="read-more">READ MORE &gt;</a>
      </div>
    </div>
  `).join('');  // join('') converts array back to single string
}

// --- FORMAT DATE ---
// Converts "2026-07-11" to "Jul 11, 2026"
function formatDate(dateStr) {
  const date = new Date(dateStr);
  const months = ['Jan','Feb','Mar','Apr','May','Jun',
                   'Jul','Aug','Sep','Oct','Nov','Dec'];
  return months[date.getMonth()] + ' ' +
         date.getDate() + ', ' +
         date.getFullYear();
}

// --- SEARCH FILTER ---
// Called every time a key is pressed in the search box
// (see onkeyup="filterArticles()" in articles.html)
function filterArticles() {
  const searchText = document.getElementById('article-search').value.toLowerCase();

  // Filter articles: by search text AND active category
  let filtered = allArticles.filter(article => {
    // Check if article title or excerpt contains the search text
    const matchesSearch = article.title.toLowerCase().includes(searchText) ||
                          article.excerpt.toLowerCase().includes(searchText);

    // Check if article matches the active category (or 'all')
    const matchesCategory = activeCategory === 'all' ||
                             article.category === activeCategory;

    return matchesSearch && matchesCategory;
  });

  renderArticles(filtered);
}

// --- CATEGORY FILTER ---
// Called when a category button is clicked
// (see onclick="filterByCategory('...')" in articles.html)
function filterByCategory(category) {
  activeCategory = category;

  // Update button styles: remove 'active' from all, add to clicked
  const buttons = document.querySelectorAll('.filter-btn');
  buttons.forEach(btn => btn.classList.remove('active'));

  // Try to mark the clicked button active. If event is available use it,
  // otherwise fallback to finding the button that matches the category string.
  if (typeof event !== 'undefined' && event.currentTarget) {
    event.currentTarget.classList.add('active');
  } else {
    // find button whose text or data-category matches the requested category
    const match = Array.from(buttons).find(b => b.textContent.trim() === category || b.getAttribute('data-category') === category);
    if (match) match.classList.add('active');
  }

  // Re-run the filter (which respects both search text and category)
  filterArticles();
}

// --- PAGE INITIALIZATION ---
// Runs when the page finishes loading
document.addEventListener('DOMContentLoaded', function() {
  // Only load articles when we're on the dedicated Articles page.
  // We check for the article grid AND at least one Articles-page-only control
  // (search input or category filters). This prevents the script from
  // injecting articles on the homepage where you render them server-side.
  const grid = document.getElementById('article-grid');
  const search = document.getElementById('article-search');
  const categoryFilters = document.getElementById('category-filters');

  if (grid && (search || categoryFilters)) {
    loadArticles();
  }
});
